import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { useParams, useNavigate } from 'react-router-dom';
import { Music, Heart, Trash2, Play, User as UserIcon, Settings } from 'lucide-react';
import { useMusic } from '../context/MusicContext';

const Profile = () => {
  const { userId } = useParams();
  const navigate = useNavigate();
  const [userProfile, setUserProfile] = useState(null);
  const [userSongs, setUserSongs] = useState([]);
  const [loading, setLoading] = useState(true);

  // Lấy hàm và dữ liệu từ MusicContext
  const { favorites, toggleLike, playMusic } = useMusic();
  const loggedInUser = JSON.parse(localStorage.getItem('user'));

  const isOwner = loggedInUser?._id === userId || loggedInUser?.id === userId;

  useEffect(() => {
    const fetchProfileData = async () => {
      setLoading(true);
      try {
        const userRes = await axios.get(`http://localhost:5000/api/songs/info/${userId}`);
        setUserProfile(userRes.data);

        const songsRes = await axios.get(`http://localhost:5000/api/songs/user/${userId}`);
        setUserSongs(songsRes.data);
      } catch (err) {
        console.error("Lỗi tải profile:", err);
      } finally {
        setLoading(false);
      }
    };
    if (userId) fetchProfileData();
  }, [userId]);

  const handleDeleteSong = async (songId) => {
    if (!window.confirm("Xóa bài hát này?")) return;
    try {
      await axios.delete(`http://localhost:5000/api/songs/${songId}`, {
        data: { userId: loggedInUser._id || loggedInUser.id, role: loggedInUser.role }
      });
      setUserSongs(userSongs.filter(s => s._id !== songId));
    } catch (err) { alert("Lỗi khi xóa bài hát."); }
  };

  if (loading) return <div style={centerStyle}>Đang tải hồ sơ...</div>;
  if (!userProfile) return <div style={centerStyle}>Không tìm thấy người dùng.</div>;

  return (
    <div style={containerStyle}>
      {/* HEADER HỒ SƠ */}
      <div style={headerCardStyle}>
        <div style={avatarWrapperStyle}>
          {userProfile.username ? userProfile.username[0].toUpperCase() : <UserIcon size={50} />}
        </div>
        <div style={infoContentStyle}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '15px' }}>
            <h1 style={nameStyle}>{userProfile.username}</h1>
            <span style={roleBadgeStyle}>{userProfile.role === 'admin' ? 'Admin' : 'Nghệ sĩ'}</span>
          </div>
          <p style={subTitleStyle}>Thành viên từ: {new Date(userProfile.createdAt).toLocaleDateString('vi-VN')}</p>
          <div style={statsRowStyle}>
            <div style={statBoxStyle}><strong>{userSongs.length}</strong> bài hát</div>
          </div>
        </div>
      </div>

      <div style={sectionTitleStyle}>
        <Music size={22} color="#1db954" />
        <h2 style={{ fontSize: '20px', margin: 0 }}>Bài hát đã đăng</h2>
      </div>

      {/* DANH SÁCH BÀI HÁT */}
      <div style={listWrapperStyle}>
        {userSongs.map((song, index) => {
          // Kiểm tra Like từ Context (Ép kiểu String để chính xác)
          const isLiked = favorites.includes(String(song._id));

          return (
            <div key={song._id} style={songCardStyle}>
              <div style={songIndexStyle}>{index + 1}</div>
              <img src={`http://localhost:5000${song.imageUrl}`} style={coverStyle} alt="" />
              
              <div style={{ flex: 1 }}>
                <div style={songNameStyle}>{song.title || song.name}</div>
                <div style={artistNameStyle}>{song.artist || song.singer}</div>
              </div>

              <div style={btnGroupStyle}>
                {/* Nút Like đồng bộ */}
                <button onClick={() => toggleLike(song._id)} style={btnTransparent}>
                  <Heart size={20} fill={isLiked ? "#1db954" : "none"} color={isLiked ? "#1db954" : "#888"} />
                </button>

                {/* Nút Phát nhạc */}
                <button onClick={() => playMusic(userSongs, index)} style={btnTransparent}>
                  <Play size={22} fill="#1db954" color="#1db954" />
                </button>
                
                {isOwner && (
                  <button onClick={() => handleDeleteSong(song._id)} style={delBtnStyle}>
                    <Trash2 size={20} />
                  </button>
                )}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

// Styles (CSS-in-JS)
const containerStyle = { maxWidth: '900px', margin: '0 auto', padding: '40px 20px', paddingBottom: '120px' };
const centerStyle = { textAlign: 'center', padding: '100px', color: '#888' };
const headerCardStyle = { display: 'flex', gap: '30px', alignItems: 'center', background: '#fff', padding: '30px', borderRadius: '24px', boxShadow: '0 4px 20px rgba(0,0,0,0.05)', marginBottom: '40px' };
const avatarWrapperStyle = { width: '100px', height: '100px', borderRadius: '50%', background: '#1db954', display: 'flex', alignItems: 'center', justifyContent: 'center', color: '#fff', fontSize: '40px', fontWeight: 'bold' };
const infoContentStyle = { flex: 1 };
const nameStyle = { fontSize: '28px', margin: 0 };
const subTitleStyle = { color: '#888', fontSize: '14px' };
const roleBadgeStyle = { background: '#f0f0f0', padding: '4px 10px', borderRadius: '12px', fontSize: '11px', fontWeight: 'bold' };
const statsRowStyle = { display: 'flex', gap: '20px', marginTop: '10px' };
const statBoxStyle = { fontSize: '14px', color: '#444' };
const sectionTitleStyle = { display: 'flex', alignItems: 'center', gap: '10px', marginBottom: '20px' };
const listWrapperStyle = { display: 'flex', flexDirection: 'column', gap: '10px' };
const songCardStyle = { display: 'flex', alignItems: 'center', padding: '12px 20px', background: '#fff', borderRadius: '12px', border: '1px solid #eee' };
const songIndexStyle = { width: '30px', color: '#bbb' };
const coverStyle = { width: '45px', height: '45px', borderRadius: '6px', marginRight: '15px', objectFit: 'cover' };
const songNameStyle = { fontWeight: '600', fontSize: '15px' };
const artistNameStyle = { fontSize: '13px', color: '#888' };
const btnGroupStyle = { display: 'flex', alignItems: 'center', gap: '15px' };
const btnTransparent = { background: 'none', border: 'none', cursor: 'pointer', padding: 5 };
const delBtnStyle = { background: 'none', border: 'none', cursor: 'pointer', color: '#ff4d4d' };

export default Profile;
